// Compliant: proper ISerializable implementation
[Serializable]
public class Foo : ISerializable
{
    private int _value;

    // Regular constructor
    public Foo(int value)
    {
        _value = value;
    }

    // Serialization constructor (protected for inheritance)
    protected Foo(SerializationInfo info, StreamingContext context)
    {
        _value = info.GetInt32("value");
    }

    // Serialization method
    public virtual void GetObjectData(SerializationInfo info, StreamingContext context)
    {
        info.AddValue("value", _value);
    }
}

// Compliant: sealed class with private constructor
[Serializable]
public sealed class Bar : ISerializable
{
    private int _value;

    private Bar(SerializationInfo info, StreamingContext context)
    {
        _value = info.GetInt32("value");
    }

    public void GetObjectData(SerializationInfo info, StreamingContext context)
    {
        info.AddValue("value", _value);
    }
}
